    learnedDemandFloorUpdatedAt = now;
} else if (now - learnedDemandFloorUpdatedAt > learnedDemandWindowMs) {
    longTermMinimumDemand = demandFloorCandidate;
    learnedDemandFloorUpdatedAt = now;
} else if (demandFloorCandidate < longTermMinimumDemand) {
    longTermMinimumDemand = demandFloorCandidate;
    learnedDemandFloorUpdatedAt = now;
} else {
    const upwardAdjustment =
        (demandFloorCandidate - longTermMinimumDemand) * learnedDemandUpwardAlpha;
    longTermMinimumDemand = Math.min(
        demandFloorCandidate,
        longTermMinimumDemand + upwardAdjustment
    );
}

context.set("learnedDemandFloor", longTermMinimumDemand);
context.set("learnedDemandFloorUpdatedAt", learnedDemandFloorUpdatedAt);

// 5. ASYMMETRIC LOGIC
// Demand: Use the Median/Defensive approach (STAY SLOW)
// This prevents the battery from discharging too fast when a spike is brief.
const defensiveTarget = Math.min(medianDemand, currentDemand);

// Solar: Keep the live value for quick visibility, but also publish the
// rolling 5-minute average so the charge controller can make steadier decisions.
const proactiveSolar = currentSolarPower;

// 6. THE "CONTINUOUS FLOW" BIAS
// If there is any solar production (>50W), we artificially lower the
// defensive demand slightly to ensure the calculation always results
// in a small positive "surplus" for the battery.
const flowBias = proactiveSolar > 50 ? 20 : 0;

node.status({
    fill: "blue",
    shape: "dot",
    text: `Mode: ${stabilityMode} | Solar (Now): ${Math.round(proactiveSolar)}W, (5min avg): ${Math.round(averageSolar)}W | Demand (Def): ${Math.round(defensiveTarget)}W`
});

msg.derived.demand = {
    current: Math.round(currentDemand),
    average: Math.round(averageDemand),
    median: Math.round(medianDemand),
    lowerBound: Math.round(lowerDemandBound),
    longTermMinimum: Math.round(longTermMinimumDemand),
    defensiveTarget: Math.round(defensiveTarget - flowBias),
    stdDev: Math.round(demandStdDev),
    trend: Math.round(demandTrend),
    trendDirection: demandTrendDirection,
    trendChanges: demandTrendChanges
};
msg.derived.solar = {
    livePower: Math.round(proactiveSolar),
    averagePower: Math.round(averageSolar),
    stdDev: Math.round(solarStdDev),
    trend: Math.round(solarTrend),
    trendDirection: solarTrendDirection,
    trendChanges: solarTrendChanges
};
msg.meta.history = {
    windowSeconds: historyWindowSeconds,
    triggerIntervalSeconds: triggerIntervalSeconds,
    triggerIntervalMs: triggerIntervalSeconds * 1000,
    samples: historySamples,
    longTermDemandWindowSeconds: learnedDemandWindowSeconds,
    trendWindowSeconds: trendWindowSeconds,
    trendSamples: trendHistorySamples
};
msg.meta.stability = {
    mode: stabilityMode,
    demand: demandStable ? "stable" : "unstable",
    solar: solarStable ? "stable" : "unstable",
    thresholds: {
        demandStdDev: demandStdDevThreshold,
        solarStdDev: solarStdDevThreshold,
        demandTrendDeadband: demandTrendDeadband,
        solarTrendDeadband: solarTrendDeadband,
        unstableTrendChanges: unstableTrendChangesThreshold
    },
    stats: {
        demandAverage: Math.round(averageDemand),
        demandLowerBound: Math.round(lowerDemandBound),
        demandLongTermMinimum: Math.round(longTermMinimumDemand),
        demandStdDev: Math.round(demandStdDev),
        demandTrend: Math.round(demandTrend),
        demandTrendDirection: demandTrendDirection,
        demandTrendChanges: demandTrendChanges,
        solarAverage: Math.round(averageSolar),
        solarStdDev: Math.round(solarStdDev),
        solarTrend: Math.round(solarTrend),
        solarTrendDirection: solarTrendDirection,
        solarTrendChanges: solarTrendChanges
    }
};
return msg;

function hasMessageValue(root, path) {
    let current = root;
    for (const segment of path.split(".")) {
        if (
            current === null ||
            current === undefined ||
            !Object.prototype.hasOwnProperty.call(current, segment)
        ) {
            return false;
        }
        current = current[segment];
    }
    return current !== undefined && current !== null;
}

function abortForMissing(requiredPaths) {
    const missing = requiredPaths.filter((path) => !hasMessageValue(msg, path));
    if (missing.length === 0) {
        return false;
    }

    const errorMessage = `Missing mandatory message fields: ${missing.join(", ")}`;
    node.status({ fill: "red", shape: "ring", text: `Missing data: ${missing.join(", ")}` });
    node.error(errorMessage, msg);
    return true;
}

if (
    abortForMissing(["data.battery.availableWh", "data.forecast.nextHourWh", "data.sun.nextRising"])
) {
    return null;
}

const data = msg.data;

// 1. DATA EXTRACTION
const availableWh = data.battery.availableWh;

// 2. NEXT HOUR FORECAST (Wh expected in the next 60 mins)
const totalNextHourWh = data.forecast.nextHourWh;

// 3. TIME CALCULATION
const now = new Date().getTime();
const sunrise = new Date(data.sun.nextRising).getTime();

// 4. DYNAMIC WINDOW ADJUSTMENT
let hoursToUsableSolar = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));

// If the Next Hour forecast is already > 50Wh, the sun is effectively "up"
// for the battery logic, even if the clock says it's early.
if (totalNextHourWh > 100) {
    // Sun is strong! Shorten the window to 1 hour to empty the battery faster.
    hoursToUsableSolar = 1.0;
} else if (totalNextHourWh > 20) {
    // Sun is starting to peek through.
    hoursToUsableSolar = Math.min(hoursToUsableSolar, 2.0);
}

// Handle edge case: If it's 2 AM and sunrise is 6 AM, hoursToSunrise = 4.
// If sunrise has already passed or is invalid, default to a small number to avoid division by zero.
// Calculate hours only if we have a valid date
let hoursToSunrise = 0.5; // Default safety
if (!isNaN(sunrise)) {
    // Math.max ensures we don't get negative numbers if sunrise just happened
    hoursToSunrise = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));
}

// 3. CALCULATION
const usableWh = Math.max(0, availableWh);
const forcedRate = Math.round(usableWh / hoursToUsableSolar);

// 4. PASS IT FORWARD
msg.derived = msg.derived || {};
msg.derived.forecast = msg.derived.forecast || {};
msg.derived.forecast.nextHourWh = totalNextHourWh;
msg.derived.forecast.hoursToUsableSolar = Math.round(hoursToUsableSolar);
msg.derived.forecast.hoursToSunrise = hoursToSunrise.toFixed(1);
msg.action = msg.action || {};
msg.action.battery = msg.action.battery || {};
msg.action.battery.discharge = msg.action.battery.discharge || {};
msg.action.battery.discharge.forcedRate = forcedRate;

node.status({ fill: "blue", shape: "ring", text: `Budget: forced ${forcedRate}W until sunrise` });

return msg;

function hasMessageValue(root, path) {
    let current = root;
    for (const segment of path.split(".")) {
        if (
            current === null ||
            current === undefined ||
            !Object.prototype.hasOwnProperty.call(current, segment)
        ) {
            return false;
        }
        current = current[segment];
    }
    return current !== undefined;
}

function abortForMissing(requiredPaths) {
    const missing = requiredPaths.filter((path) => !hasMessageValue(msg, path));
    if (missing.length === 0) {
        return false;
    }

    const errorMessage = `Missing mandatory message fields: ${missing.join(", ")}`;
    node.status({ fill: "red", shape: "ring", text: `Missing data: ${missing.join(", ")}` });
    node.error(errorMessage, msg);
    return true;
}

if (
    abortForMissing([
        "data.grid.power",
        "data.battery.dischargePower",
        "derived.demand.defensiveTarget",
        "derived.demand.lowerBound",
        "derived.demand.longTermMinimum",
        "derived.solar.livePower",
        "action.battery.discharge.forcedRate"
    ])
) {
    return null;
}

// 1. DATA RETRIEVAL
const data = msg.data;
const derived = msg.derived;
const action = msg.action;
const gridPower = data.grid.power;
const currentBatteryOut = data.battery.dischargePower;
const calculatedDemand = derived.demand.defensiveTarget;
const demandLowerBound = derived.demand.lowerBound;
const demandLongTermMinimum = derived.demand.longTermMinimum;
const solarPower = derived.solar.livePower;
const forcedDischarge = action.battery.discharge.forcedRate;
const stopRequested = action.battery.discharge.stopRequested === true;
const blockedByLowSoc = action.battery.discharge.blockedByLowSoc === true;

if (stopRequested || blockedByLowSoc) {
    context.set("lastCommand", 0);

    msg.action = action;
    msg.action.battery = msg.action.battery || {};
    msg.action.battery.discharge = msg.action.battery.discharge || {};
    msg.action.battery.discharge.commandPower = 0;
    msg.action.battery.discharge.requiredChange = 0;
    msg.action.battery.discharge.isStable = true;
    msg.action.battery.discharge.gridPower = Math.round(gridPower);

    node.status({
        fill: "red",
        shape: "ring",
        text: blockedByLowSoc ? "Discharge blocked by low SoC" : "Discharge stop requested"
    });
    return msg;
}

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
//   1. The Deadband(deadband = 75): This is your Cycle - Killer.
//                                   It stops the battery from chasing the "ghosts" of small appliances.
//                                   If your fridge compressor flickers, the battery ignores it.
//
//   2. The Safety Buffer(-30): By aiming for a 30W import, you create a "cushion."
//                              When a cloud disappears and solar spikes, you have 30W of "room" before
//                              starting to feed-in into public grid.
//
//   3. The EMA(alpha = 0.9): This solves the 50s latency of smart meter and battery.
//                            Instead of jumping to a new value every 20s (init trigger) and
//                            overshooting, the battery "slides" toward the new value. This reduces the
//                            chemical stress on the LiFePO4 cells.

const targetBuffer = -50; // Aim for 50W import to prevent feed-in
const deadband = 50; // Ignore fluctuations smaller than 50W
const alpha = 0.3; // EMA Smoothing factor (0.1 = very slow, 0.9 = very fast)
const sustainTolerance = 30; // Treat demand near the lower bound as baseline night load

// 3. CALCULATION
// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects, that there is more solar power than demand,
// e.g. 10W (solar) - 300W (demand) - (-30) = -260W to discharge
//       0W (solar) - 50W (demand) - (-30) = -20W to discharge
//     100W (solar) - 200W (demand) - (-30) = -70W to discharge
//       0W (solar) - 200W (demand) - (-30) = -170W to discharge
//       1W (solar) - 201W (demand) - (-30) = -170W to discharge
//       0W (solar) - (-50)W (demand) - (-30) = 80W to adjust or even stop discharging (discharging is at least 50W)
let requiredChange = solarPower - calculatedDemand - targetBuffer;

// 4. THE CYCLE GUARD (Dynamic Deadband)
// If the requiredChange is small AND we aren't "exporting", stay still to save battery cycles
if (Math.abs(requiredChange) < deadband && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Done (deadband) - Stable power - finish (calculated change is ${Math.round(requiredChange)}W, grid power: ${Math.round(gridPower)}W)`
    });
    return null; // Stop the message here; no command sent to inverter
}

// 5. EMA SMOOTHING (The "Lag Compensator")
let lastCommand = context.get("lastCommand") || 0;
let rawCommand = requiredChange * -1; // invert to represent the power gap required from battery

if (rawCommand < 0 && currentBatteryOut > 0) {
    // demand is larger than solar power but still solar power available
    rawCommand = (requiredChange - targetBuffer - currentBatteryOut) * -1; // 80W - 30 - 60 = -10 -> reduce discharging before stopping
}

// Apply Exponential Moving Average
let smoothedCommand = rawCommand * alpha + lastCommand * (1 - alpha);

const activeDischargeReference = Math.max(currentBatteryOut, lastCommand);
const isDischargingActive = activeDischargeReference > 5;
const baselineDemandFloor = Math.max(demandLowerBound, demandLongTermMinimum);
const isAtDemandFloor = calculatedDemand <= baselineDemandFloor + sustainTolerance;
const lowerBoundDischargeFloor = Math.max(0, baselineDemandFloor - solarPower);
const dischargeSustainFloor = Math.min(
    forcedDischarge,
    activeDischargeReference,
    lowerBoundDischargeFloor
);
const sustainDischargeActive =
    isDischargingActive &&
    forcedDischarge > 0 &&
    gridPower > 0 &&
    isAtDemandFloor &&
    dischargeSustainFloor > 0;

if (sustainDischargeActive && smoothedCommand < dischargeSustainFloor) {
    smoothedCommand = dischargeSustainFloor;
}

// 5. THE ZERO-EXPORT DEFENSE (The "No-Penalty" Guard)
// --> EMERGENCY BRAKE
if (gridPower < 0) {
    smoothedCommand = Math.max(0, currentBatteryOut + gridPower + targetBuffer);
}

smoothedCommand = Math.min(smoothedCommand, forcedDischarge * 2.5);

// Only output if the command actually changed significantly (e.g., > 5W)
if (Math.abs(smoothedCommand - lastCommand) < 5 && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Idle (deadband) - Hardly changed power - finish: ${Math.round(smoothedCommand)}W, grid Power ${gridPower}W`
    });
    return null;
}

// 6. FINAL OUTPUT & PERSISTENCE
context.set("lastCommand", smoothedCommand);

msg.action = action;
msg.action.battery = msg.action.battery || {};
msg.action.battery.discharge = msg.action.battery.discharge || {};
msg.action.battery.discharge.commandPower = Math.round(smoothedCommand);
msg.action.battery.discharge.requiredChange = Math.round(requiredChange);
msg.action.battery.discharge.isStable = Math.abs(requiredChange) < deadband;
msg.action.battery.discharge.gridPower = Math.round(gridPower);
msg.action.battery.discharge.baselineDemandFloor = Math.round(baselineDemandFloor);
msg.action.battery.discharge.sustainFloor = Math.round(dischargeSustainFloor);
msg.action.battery.discharge.sustainActive = sustainDischargeActive;

node.status({
    fill: "green",
    shape: "dot",
    text: sustainDischargeActive
        ? `Discharge sustain @ ${Math.round(smoothedCommand)}W`
        : `Calculated Power (smoothed): ${Math.round(smoothedCommand)}W`
});
return msg;
